create extension if not exists "pgcrypto";
create type distribution_frequency as enum ('weekly','biweekly','custom'); create type transaction_type as enum ('salary','unlock','transfer','saving','fee','reward'); create type family_role as enum ('owner','parent','member','child');
create table profiles(id uuid primary key references auth.users(id) on delete cascade, full_name text not null, phone text unique, preferred_language text not null default 'ar', default_currency char(3) not null default 'SAR', pin_hash text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table salary_plans(id uuid primary key default gen_random_uuid(), user_id uuid not null references profiles(id) on delete cascade, name text not null, salary_amount numeric(14,2) not null check(salary_amount>=0), currency char(3) not null default 'SAR', frequency distribution_frequency not null, rollover_enabled boolean not null default true, monthly_unlock_limit int not null default 2, active boolean not null default true, created_at timestamptz not null default now());
create table allocations(id uuid primary key default gen_random_uuid(), user_id uuid not null references profiles(id) on delete cascade, plan_id uuid not null references salary_plans(id) on delete cascade, period_start date not null, period_end date not null, amount numeric(14,2) not null check(amount>=0), available_at timestamptz not null, locked boolean not null default true, unlocked_at timestamptz, unique(plan_id,period_start));
create table wallets(id uuid primary key default gen_random_uuid(), user_id uuid not null unique references profiles(id) on delete cascade, available_balance numeric(14,2) not null default 0, locked_balance numeric(14,2) not null default 0, currency char(3) not null default 'SAR');
create table transactions(id uuid primary key default gen_random_uuid(), user_id uuid not null references profiles(id) on delete cascade, wallet_id uuid references wallets(id), allocation_id uuid references allocations(id), type transaction_type not null, amount numeric(14,2) not null, currency char(3) not null default 'SAR', description text not null, metadata jsonb not null default '{}', created_at timestamptz not null default now());
create table savings_goals(id uuid primary key default gen_random_uuid(), user_id uuid not null references profiles(id) on delete cascade, title text not null, target_amount numeric(14,2) not null check(target_amount>0), current_amount numeric(14,2) not null default 0, auto_save_percent numeric(5,2) not null default 0, due_date date, completed_at timestamptz, created_at timestamptz not null default now());
create table families(id uuid primary key default gen_random_uuid(), owner_id uuid not null references profiles(id) on delete cascade, name text not null, created_at timestamptz not null default now());
create table family_members(id uuid primary key default gen_random_uuid(), family_id uuid not null references families(id) on delete cascade, user_id uuid not null references profiles(id) on delete cascade, role family_role not null default 'member', spending_limit numeric(14,2), permissions jsonb not null default '{}', unique(family_id,user_id));
create table notifications(id uuid primary key default gen_random_uuid(), user_id uuid not null references profiles(id) on delete cascade, title text not null, body text not null, read_at timestamptz, data jsonb not null default '{}', created_at timestamptz not null default now());
create table audit_logs(id uuid primary key default gen_random_uuid(), actor_id uuid, action text not null, table_name text not null, row_id uuid, old_data jsonb, new_data jsonb, created_at timestamptz not null default now());
create index on salary_plans(user_id,active); create index on allocations(user_id,available_at); create index on transactions(user_id,created_at desc); create index on savings_goals(user_id,completed_at); create index on notifications(user_id,read_at);
create or replace function touch_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$; create trigger profiles_touch before update on profiles for each row execute function touch_updated_at();
alter table profiles enable row level security; alter table salary_plans enable row level security; alter table allocations enable row level security; alter table wallets enable row level security; alter table transactions enable row level security; alter table savings_goals enable row level security; alter table families enable row level security; alter table family_members enable row level security; alter table notifications enable row level security;
create policy own_profiles on profiles for all using (auth.uid()=id) with check (auth.uid()=id); create policy own_plans on salary_plans for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy own_allocations on allocations for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy own_wallets on wallets for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy own_transactions on transactions for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy own_goals on savings_goals for all using (auth.uid()=user_id) with check (auth.uid()=user_id); create policy own_notifications on notifications for all using (auth.uid()=user_id) with check (auth.uid()=user_id);
